code = """import pandas as pd
import json

# Load Cases
with open(locals()['var_function-call-16713065332506572463'], 'r') as f:
    cases_data = json.load(f)
cases_df = pd.DataFrame(cases_data)

# Load Accounts
accounts_data = locals()['var_function-call-16713065332506571828']
accounts_df = pd.DataFrame(accounts_data)

# Clean IDs
cases_df['clean_account_id'] = cases_df['accountid'].str.lstrip('#')
accounts_df['clean_id'] = accounts_df['Id'].str.lstrip('#')

# Convert dates
cases_df['CreatedDate'] = pd.to_datetime(cases_df['createddate'])
cases_df['ClosedDate'] = pd.to_datetime(cases_df['closeddate'])

# Define Time Window (Rolling 18 months up to today)
# 2022-10-26
# Start: 2021-04-26
start_date = pd.Timestamp('2021-04-26').tz_localize('UTC')
end_date = pd.Timestamp('2022-10-26 23:59:59.999999').tz_localize('UTC')

# Filter Cases
mask = (cases_df['ClosedDate'] >= start_date) & (cases_df['ClosedDate'] <= end_date)
filtered_cases = cases_df[mask].copy()

# Calculate Duration
filtered_cases['duration'] = filtered_cases['ClosedDate'] - filtered_cases['CreatedDate']
filtered_cases['duration_hours'] = filtered_cases['duration'].dt.total_seconds() / 3600.0

# Join
merged_df = filtered_cases.merge(accounts_df, left_on='clean_account_id', right_on='clean_id', how='inner')

# Group by State
state_stats = merged_df.groupby('ShippingState').agg(
    avg_duration=('duration_hours', 'mean'),
    count=('duration_hours', 'count')
).reset_index()
state_stats = state_stats.sort_values('avg_duration')

print("__RESULT__:")
print(state_stats.to_json(orient='records'))"""

